/** name (lowercase) → code. Built once; both half-names map to their code. */
const NAME_TO_CODE = (() => {
  const m = new Map();
  REGION_NAMES.forEach((pair, code) => {
    for (const name of pair) if (!m.has(name)) m.set(name, code);
  });
  return m;
})();

/**
 * Both region names for a code (the two halves).
 * @param {number} code  integer in [0,192)
 * @returns {[string,string]|null}
 */
export function regionNames(code) {
  return isValidCellId(code) ? REGION_NAMES[code] : null;
}

/**
 * A region name for a code. With a coordinate, returns the name for the half
 * the point is in (closest to the user's location); otherwise the first half.
 * @param {number} code
 * @param {number} [lat]
 * @param {number} [lng]
 * @returns {string|null}
 */
export function regionName(code, lat, lng) {
  if (!isValidCellId(code)) return null;
  const half = (typeof lat === 'number' && typeof lng === 'number') ? geoCellHalf(lat, lng) : 0;
  return REGION_NAMES[code][half];
}

/**
 * Region code for a region name (case-insensitive). Either half-name works.
 * @param {string} name
 * @returns {number|null}
 */
export function regionCode(name) {
  if (typeof name !== 'string') return null;
  const code = NAME_TO_CODE.get(name.trim().toLowerCase());
  return code === undefined ? null : code;
}

/**
 * Resolve a region token — a NAME (either half) or a numeric code — to its
 * 8-bit code. Accepts 'useast', 'USEAST', '0x89', '137', or 137.
 * @param {string|number} token
 * @returns {number|null}
 */
export function resolveRegion(token) {
  if (typeof token === 'number') return isValidCellId(token) ? token : null;
  if (typeof token !== 'string') return null;
  const t = token.trim();
  const byName = regionCode(t);
  if (byName !== null) return byName;
  const n = /^0x[0-9a-f]+$/i.test(t) ? parseInt(t, 16)
          : /^\d+$/.test(t)          ? parseInt(t, 10)
          : NaN;
  return isValidCellId(n) ? n : null;
}

/**
 * The location-appropriate region name for a (lat,lng): the name of the half
 * the coordinate falls in.
 * @param {number} lat
 * @param {number} lng
 * @returns {string}
 */
export function regionNameForLatLng(lat, lng) {
  const code = geoCellId(lat, lng, 8);
  return REGION_NAMES[code][geoCellHalf(lat, lng)];
}

if (REGION_NAMES.length !== S2_CELL_COUNT) {
  throw new Error(
    `region-names.js: have ${REGION_NAMES.length} regions, expected ${S2_CELL_COUNT}`);
}
